const body = $('Design Request Webhook').first().json.body || {};
const fetchDataUrl = async (url) => {
  const response = await this.helpers.httpRequest({ method: 'GET', url, encoding: 'base64', json: false, timeout: 120000 });
  const mime = url.match(/\.jpe?g($|\?)/i) ? 'image/jpeg' : url.match(/\.webp($|\?)/i) ? 'image/webp' : 'image/png';
  return 'data:' + mime + ';base64,' + response;
};
const referenceImages = Array.isArray(body.referenceImageFiles) ? [...body.referenceImageFiles] : [];
for (const url of (Array.isArray(body.referenceImageUrls) ? body.referenceImageUrls : [])) {
  try { referenceImages.push(await fetchDataUrl(url)); } catch (e) {}
}
const mimeOf = (dataUrl) => (typeof dataUrl === 'string' && dataUrl.match(/^data:([^;]+);base64,/))?.[1] || 'image/png';
const designType = body.designType || 'the selected design format';
const generationMode = body.generationMode || 'single';
const sampleRuleBenchmark = JSON.stringify({
  styleName: 'STYLE 01 — CINEMATIC BANNER / Black & White Documentary',
  designIdentity: { feeling: 'documentary poster or vintage magazine feature', useFor: ['deep-dive features','historical retrospectives','behind-the-scenes explorations'], corePrinciple: 'One strong photograph. One loud red line. Everything else gets out of the way.' },
  canvas: { dimensions: '1280x720', aspectRatio: '16:9', colorMode: 'RGB/sRGB', safeZone: 'keep key subjects clear of bottom 60px timestamp overlay', export: 'JPG under 2MB' },
  visualTreatment: { imageSelection: 'single full-bleed wide photo with real environmental depth and expressive faces', blackWhite: 'saturation 0, hard contrast, blacks RGB 5-15, whites RGB 240-250, optional <=5% warm tint', texture: 'film grain 4-6% opacity' },
  typography: { typeface: 'heavy condensed sans with roughness such as Anton/Bebas Neue/Druk Wide', weight: '800-900', case: 'ALL CAPS', color: '#A32D2D to #B8322E', capHeight: '80-95px per line, 110-130px for very short copy', lineHeight: '0.9', tracking: '-5 to -15', alignment: 'left, x=40-60px', texture: 'optional distressed overlay 10-15%' },
  copyPlacement: { exactCopy: 'never add, reorder, punctuate, or rewrite supplied words', lineRules: '1-2 words single line; 3-5 words two balanced lines; ask for shorter copy at 6+ words', position: 'midline y≈220-440; text cuts through upper torso/lower-face region, not empty sky' },
  colorSystem: { allowed: ['#0A0A0A photo blacks','#F4F4F4 photo whites','#A32D2D headline red','#B8322E alternate red'], constraint: 'only black, white, and one red; no secondary hue' },
  buildSteps: ['set 1280x720 canvas','place and grade full-bleed photo','set exact supplied headline','optionally distress text','review at 240x135 thumbnail','export JPG quality 85-92'],
  doDont: { do: ['one full-bleed photo','true high-contrast B&W','text crops into subject','exact supplied copy'], dont: ['collages','color photo','floating text in empty space','secondary accent colors','3+ line headline'] },
  prePublishChecklist: ['canvas is 1280x720','single photo fills canvas','B&W contrast with grain','copy exact','headline deep red all caps','tested at thumbnail size']
});
const question = 'Analyze ONLY the uploaded reference design template image(s). Return strict JSON, not prose, with this exact top-level structure: {"designIdentity":{},"canvas":{},"visualTreatment":{},"typography":{},"copyPlacement":{},"colorSystem":{},"assetRules":{},"composition":{},"buildSteps":[],"doDont":{},"prePublishChecklist":[],"qualityNotes":{}}. Target format: ' + designType + '. Output structure: ' + generationMode + '. Use this SAMPLE VALID TEMPLATE RULE as a structural and detail benchmark, but do not copy its style unless the uploaded reference matches it: ' + sampleRuleBenchmark + ' Do not generate the final design. Do not analyze user asset/subject images. Do not include base64 data. Be as specific as the cinematic B&W banner sample rule: concrete dimensions, coordinates/zones, font weights, colors, line breaks, image treatment, constraints, and checklist.';
const request = {
  question,
  uploads: referenceImages.slice(0, 3).map((data, idx) => ({
    data,
    type: 'file',
    name: 'template-reference-' + (idx + 1) + '.' + (mimeOf(data).split('/')[1] || 'png'),
    mime: mimeOf(data)
  }))
};
const fallbackRules = {
  designIdentity: { styleName: 'Reference-derived high-fidelity design system', useCase: designType, mood: 'template-faithful, editorial, asset-led', principle: 'Preserve the reference layout grammar while replacing subjects with user assets.' },
  canvas: { dimensions: designType === 'Twitter Banner' ? '1500x500' : designType === 'Event Flyer' ? '1080x1350' : designType === 'LinkedIn Carousel' || generationMode === 'carousel' ? '1080x1080' : '1280x720', aspectRatio: designType === 'Twitter Banner' ? '3:1' : designType === 'Event Flyer' ? '4:5' : designType === 'LinkedIn Carousel' || generationMode === 'carousel' ? '1:1' : '16:9', safeZone: 'Keep primary faces/assets clear of outer 48px and UI overlays; keep text within readable center/left zones.', export: 'sRGB PNG/JPG, high quality' },
  visualTreatment: { imageTreatment: 'Use reference-derived contrast, depth, texture, background treatment, and lighting style.', background: 'Full-canvas design field, no empty default gradient unless present in the reference.', effects: ['reference-matched shadows/highlights', 'subtle texture only when reference supports it'] },
  typography: { family: 'Match reference category; use heavy display sans when uncertain', weight: '800-900 for headline', case: 'Preserve supplied words; follow reference casing', color: 'Use extracted palette, never random accent colors', size: 'Scale to reference hierarchy', lineHeight: 'Tight display leading for headlines', alignment: 'Match reference text alignment and zones' },
  copyPlacement: { exactCopy: 'Render supplied caption exactly; do not invent words.', lineBreaks: 'Choose balanced line breaks; avoid 3+ headline lines unless carousel copy requires it.', position: 'Place text in the same functional zone as reference without covering key asset faces.' },
  colorSystem: { palette: ['reference-background', 'reference-primary-text', 'reference-accent', 'neutral-highlight'], constraints: 'Limit to the reference palette; do not introduce unrelated hues.' },
  assetRules: { usage: 'User asset images are mandatory final subjects, not optional inspiration.', placement: 'Place assets in the subject/content zones implied by the reference.', fidelity: 'Preserve recognizable asset category, clothing/product silhouette, and major visual features unless safety rules prevent exact reproduction.' },
  composition: { hierarchy: 'Reference layout hierarchy first, user assets second, exact caption third.', spacing: 'Keep margins/gutters consistent with the reference.', mode: generationMode },
  buildSteps: ['Set canvas and safe zones', 'Extract reference palette, typography, composition zones', 'Place user asset images as primary subjects', 'Render exact caption in reference text zone', 'Apply reference-matched lighting/texture/effects', 'Review thumbnail readability'],
  doDont: { do: ['Use user assets visibly', 'Match reference zones and palette', 'Keep copy exact'], dont: ['Do not ignore assets', 'Do not invent text', 'Do not add unrelated colors', 'Do not use generic stock subjects'] },
  prePublishChecklist: ['Canvas matches requested format', 'Template rules are visible in composition', 'User asset images are clearly present', 'Caption is exact and legible', 'Palette and typography match reference', 'No dummy/local fallback artifacts']
};
try {
  const raw = await this.helpers.httpRequest({
    method: 'POST',
    url: 'http://flowise:3000/api/v1/prediction/11111111-1111-4111-8111-111111111111',
    headers: { 'Content-Type': 'application/json', 'Origin': 'http://localhost:5000' },
    body: request,
    json: true,
    timeout: 120000
  });
  const rawRules = raw.layoutRules || raw.json || raw.answer || raw.text || {};
  const mergedRules = typeof rawRules === 'object' && rawRules && Object.keys(rawRules).length >= 8 ? rawRules : { ...fallbackRules, flowiseRaw: rawRules };
  return [{ json: { ...raw, source: raw.source || 'flowise-chatflow', received: { ...(raw.received || {}), question }, question, layoutRules: mergedRules, normalizedByWorkflow: true } }];
} catch (error) {
  return [{ json: { source: 'flowise-chatflow', chatflowId: '11111111-1111-4111-8111-111111111111', mode: generationMode, slideCount: generationMode === 'carousel' ? Math.max((body.userCopyTexts || []).length, (body.userAssetUrls || []).length, 1) : 1, ok: false, error: error.message, layoutRules: fallbackRules, received: { question }, question, normalizedByWorkflow: true }}];
}

const flowise = $('Call Flowise Layout Rules').first().json;
const gemini = $('Call Gemini Image Model').first().json;
const requestBody = $('Design Request Webhook').first().json.body || {};
const parts = gemini?.candidates?.[0]?.content?.parts || [];
const imagePart = parts.find(p => p.inlineData);
const textPart = parts.find(p => p.text);
const refCount = (Array.isArray(requestBody.referenceImageFiles) ? requestBody.referenceImageFiles.length : 0) + (Array.isArray(requestBody.referenceImageUrls) ? requestBody.referenceImageUrls.length : 0);
const assetCount = (Array.isArray(requestBody.userAssetFiles) ? requestBody.userAssetFiles.length : 0) + (Array.isArray(requestBody.userAssetUrls) ? requestBody.userAssetUrls.length : 0);
const rules = flowise?.layoutRules || {};
const required = ['designIdentity','canvas','visualTreatment','typography','copyPlacement','colorSystem','assetRules','composition','buildSteps','doDont','prePublishChecklist'];
const present = required.filter(key => rules && Object.prototype.hasOwnProperty.call(rules, key));
const serializedRules = JSON.stringify(rules);
const templateRuleQuality = {
  score: present.length,
  requiredCount: required.length,
  present,
  missing: required.filter(key => !present.includes(key)),
  characterCount: serializedRules.length,
  richEnough: present.length >= 9 && serializedRules.length >= 1800,
  benchmark: 'cinematic-bw-banner-rule-depth'
};
return [{ json: { source: 'n8n-live-orchestrator', n8nWorkflow: 'Deconstruct AI Live Orchestrator', flowise, templateRuleQuality, gemini: { attempted: true, ok: Boolean(imagePart), model: gemini?.model || 'gemini-3-pro-image', finishReason: gemini?.candidates?.[0]?.finishReason || null, finishMessage: gemini?.candidates?.[0]?.finishMessage || null, error: gemini?.error || null, modelAttempts: gemini?.modelAttempts || [], noImageAfterFallbacks: Boolean(gemini?.noImageAfterFallbacks), httpStatus: gemini?.httpStatus || null, httpOk: gemini?.httpOk || false, retryAttempt: requestBody.retryAttempt || 0, safeImageMode: Boolean(requestBody.safeImageMode), text: textPart?.text || null, image: imagePart ? { mimeType: imagePart.inlineData.mimeType, data: imagePart.inlineData.data } : null, assetImageCount: gemini?.assetImageCount || assetCount, conditioning: { templateMode: requestBody.templateMode || 'ad-hoc-generation', generationMode: requestBody.generationMode || 'single', existingTemplateRulesUsed: Boolean(requestBody.existingTemplateRules), referenceImageCount: refCount, assetImageCount: assetCount, usedInlineImageParts: assetCount > 0, assetRequiredInPrompt: true } }, evidence: { n8n: true, flowise: flowise.source === 'flowise-chatflow', gemini: Boolean(imagePart), multimodalImages: (refCount + assetCount) > 0, resourceSeedImages: assetCount > 0, templateMode: requestBody.templateMode || 'ad-hoc-generation', generationMode: requestBody.generationMode || 'single', templateRuleQuality, flowiseChatflowId: flowise.chatflowId, timestamp: new Date().toISOString() } } }];

const body = $('Design Request Webhook').first().json.body || {};
const fetchDataUrl = async (url) => {
  const response = await this.helpers.httpRequest({ method: 'GET', url, encoding: 'base64', json: false, timeout: 120000 });
  const mime = url.match(/\.jpe?g($|\?)/i) ? 'image/jpeg' : url.match(/\.webp($|\?)/i) ? 'image/webp' : 'image/png';
  return 'data:' + mime + ';base64,' + response;
};
const flowise = $('Call Flowise Layout Rules').first().json || {};
const caption = body.caption || (body.userCopyTexts || [''])[0] || '';
const designType = body.designType || 'design';
const generationMode = body.generationMode || 'single';
const templateMode = body.templateMode || 'ad-hoc-generation';
const templateRules = flowise.layoutRules || flowise.json || flowise.text || flowise.answer || flowise;
const parts = [];
const toInlinePart = (dataUrl) => {
  if (!dataUrl || typeof dataUrl !== 'string') return null;
  const match = dataUrl.match(/^data:([^;]+);base64,(.+)$/);
  if (!match) return null;
  return { inlineData: { mimeType: match[1], data: match[2] } };
};
const assetImages = Array.isArray(body.userAssetFiles) ? [...body.userAssetFiles] : [];
for (const url of (Array.isArray(body.userAssetUrls) ? body.userAssetUrls : [])) {
  try { assetImages.push(await fetchDataUrl(url)); } catch (e) {}
}
parts.push({ text: 'TASK: create a finished ' + designType + ' design by applying TEMPLATE RULES to the uploaded SUBJECT ASSET IMAGE(S). Output structure: ' + generationMode + '. CRITICAL ASSET RULE: this is an image-composition/editing task, not a generic illustration task. The uploaded asset image pixels/visual subject must be plainly visible in the final image as the hero cutout, framed photo panel, product/portrait card, or main collage element. Preserve the asset subject category, pose/silhouette, clothing/product details, colors, and recognizable visual content. Do NOT invent replacement people/products. Do NOT use template reference images as final subjects. If a perfect stylistic blend is hard, place the asset as a clear foreground photo/card over the template-inspired background. Render the exact caption text only: "' + caption + '". Return a finished image, not JSON. Template mode: ' + templateMode + '. Rich template rules JSON: ' + JSON.stringify(templateRules) });
assetImages.slice(0, 4).forEach((img, idx) => {
  parts.push({ text: 'SUBJECT_ASSET_IMAGE_' + (idx + 1) + ' — MANDATORY PIXEL-VISIBLE INPUT. The final image must visibly contain this uploaded asset. A reviewer comparing source asset to output must be able to point to where it appears. Do not substitute a generic person/object. Use it as the main foreground subject or as a clear photo panel if needed.' });
  const part = toInlinePart(img); if (part) parts.push(part);
});
parts.push({ text: assetImages.length
  ? 'FINAL CHECK BEFORE ANSWERING WITH IMAGE: Does the output visibly include the uploaded SUBJECT_ASSET_IMAGE as a main element? If not, revise the image so the asset is obvious. Caption must remain exact: "' + caption + '".'
  : 'No user asset image was supplied; generate from caption and template rules only.' });
const request = { contents: [{ parts }], generationConfig: { responseModalities: ['TEXT','IMAGE'] } };
const getImagePart = (json) => (json?.candidates?.[0]?.content?.parts || []).find(p => p.inlineData);
try {
  const apiKey = $env.GEMINI_API_KEY;
  const primaryModel = $env.GEMINI_IMAGE_MODEL || 'gemini-3-pro-image';
  const fallbackModels = ($env.GEMINI_IMAGE_FALLBACK_MODELS || '')
    .split(',')
    .map(m => m.trim())
    .filter(Boolean);
  const allowedFallbacks = fallbackModels.filter(model => /pro-image/i.test(model));
  const models = [...new Set([primaryModel, ...allowedFallbacks])];
  if (!apiKey) return [{ json: { error: { message: 'GEMINI_API_KEY is not configured' }, candidates: [], model: primaryModel, attemptedModels: models } }];

  const attempts = [];
  let lastJson = null;
  for (const model of models) {
    try {
      const json = await this.helpers.httpRequest({
        method: 'POST',
        url: 'https://generativelanguage.googleapis.com/v1beta/models/' + model + ':generateContent?key=' + apiKey,
        headers: { 'Content-Type': 'application/json' },
        body: request,
        json: true,
        timeout: 180000
      });
      json.httpStatus = 200;
      json.httpOk = true;
      json.model = model;
      json.assetImageCount = assetImages.length;
      json.attemptedModels = models;
      const candidate = json?.candidates?.[0] || {};
      attempts.push({ model, httpOk: true, hasImage: Boolean(getImagePart(json)), finishReason: candidate.finishReason || null, finishMessage: candidate.finishMessage || null, text: candidate.content?.parts?.find(p => p.text)?.text || null });
      json.modelAttempts = attempts;
      lastJson = json;
      if (getImagePart(json)) return [{ json }];
    } catch (modelError) {
      attempts.push({ model, httpOk: false, hasImage: false, error: modelError.message });
      lastJson = { error: { message: modelError.message }, candidates: [], httpStatus: 0, httpOk: false, model, assetImageCount: assetImages.length, attemptedModels: models, modelAttempts: attempts };
    }
  }
  lastJson.noImageAfterFallbacks = true;
  lastJson.modelAttempts = attempts;
  return [{ json: lastJson }];
} catch (error) {
  return [{ json: { error: { message: error.message }, candidates: [], httpStatus: 0, httpOk: false, model: $env.GEMINI_IMAGE_MODEL || 'gemini-3-pro-image', assetImageCount: assetImages.length } }];
}
